module gated_flip_flop(  
    input clk,  
    input rst,  
    input clk_en,  
    input d,  
    output reg q  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            q <= 1'b0;  
        else if (clk_en)  
            q <= d;  
    end  
endmodule
